const body = $input.first().json.body;

const src = body.source || {};
if (!src.database) {
  throw new Error('ClickHouse source database is required');
}
const chHost = src.host || 'localhost';
const chPort = src.port || 8123;
const chUser = src.user || 'default';
const chPassword = src.password || '';
const chDatabase = src.database;

const dest = body.destination || {};
const connectionId = dest.connection_id !== undefined ? dest.connection_id : 0;

const synHost = dest.host || 'localhost';
const synPort = dest.port || 3306;
const synUser = dest.user || 'root';
const synPassword = dest.password || '';
const synDatabase = dest.database || 'syntheta_db';

return [{
  json: {
    chHost, chPort, chUser, chPassword, chDatabase,
    synHost, synPort, synUser, synPassword, synDatabase,
    connectionId
  }
}];

const config = $('Parse Request').first().json;
const response = $input.first().json;

let allTables = [];
if (response.data) {
  allTables = response.data.map(row => row.name);
}

if (allTables.length === 0) {
  throw new Error('No tables found in ClickHouse database: ' + config.chDatabase);
}

return allTables.map(name => ({
  json: {
    tableName: name,
    chHost: config.chHost, chPort: config.chPort,
    chUser: config.chUser, chPassword: config.chPassword,
    chDatabase: config.chDatabase,
    synHost: config.synHost, synPort: config.synPort,
    synUser: config.synUser, synPassword: config.synPassword,
    synDatabase: config.synDatabase,
    connectionId: config.connectionId
  }
}));

const response = $input.first().json;
const ctx = $('Current Table').first().json;
const tableName = ctx.tableName;

// Always use CH database name as target, original table names (no prefix)
const targetDb = ctx.chDatabase;
const mysqlTable = tableName;

let rows = [];
if (response.data) {
  rows = response.data;
} else if (Array.isArray(response)) {
  rows = response;
}

if (rows.length === 0) {
  return [{ json: { status: 'skipped', table: tableName, reason: 'no data', createDbSQL: 'SELECT 1', dropSQL: 'SELECT 1', createSQL: 'SELECT 1', insertSQL: 'SELECT 1' } }];
}

function inferMySQLType(value) {
  if (value === null || value === undefined) return 'VARCHAR(500)';
  if (typeof value === 'boolean') return 'TINYINT(1)';
  if (typeof value === 'number') {
    return Number.isInteger(value) ? 'INT' : 'DECIMAL(20,6)';
  }
  if (typeof value === 'string') {
    if (/^\d{4}-\d{2}-\d{2}(T|\s)\d{2}:\d{2}/.test(value)) return 'DATETIME';
    if (/^-?\d+$/.test(value)) return 'INT';
    if (/^-?\d+\.\d+$/.test(value)) return 'DECIMAL(20,6)';
    if (value.length > 500) return 'TEXT';
    return 'VARCHAR(500)';
  }
  return 'TEXT';
}

function sanitizeValue(value, targetType) {
  if (value === null || value === undefined) return null;
  if (typeof value === 'number' && (isNaN(value) || !isFinite(value))) return null;
  if (targetType === 'DATETIME' && typeof value === 'string') {
    if (/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}$/.test(value)) return value;
    const d = new Date(value);
    return isNaN(d.getTime()) ? null : d.toISOString().slice(0, 19).replace('T', ' ');
  }
  return value;
}

function escapeSQL(val) {
  if (val === null) return 'NULL';
  if (typeof val === 'number') return String(val);
  return "'" + String(val).replace(/'/g, "''") + "'";
}

const sample = rows[0];
const columnDefs = [];
const colNames = [];
const schema = {};
for (const [key, value] of Object.entries(sample)) {
  const mysqlType = inferMySQLType(value);
  columnDefs.push('`' + key + '` ' + mysqlType);
  colNames.push(key);
  schema[key] = mysqlType;
}

const fullTable = '`' + targetDb + '`.`' + mysqlTable + '`';
const createDbSQL = 'CREATE DATABASE IF NOT EXISTS `' + targetDb + '`';
const dropSQL = 'DROP TABLE IF EXISTS ' + fullTable;
const createSQL = 'CREATE TABLE ' + fullTable + ' (' + columnDefs.join(', ') + ') ENGINE=InnoDB DEFAULT CHARSET=utf8mb4';

const valueRows = rows.map(row => {
  const vals = colNames.map(col => escapeSQL(sanitizeValue(row[col], schema[col])));
  return '(' + vals.join(',') + ')';
});
const insertSQL = 'INSERT INTO ' + fullTable + ' (`' + colNames.join('`,`') + '`) VALUES ' + valueRows.join(',');

return [{
  json: {
    createDbSQL, dropSQL, createSQL, insertSQL,
    mysqlTable, tableName, targetDatabase: targetDb,
    rowCount: rows.length
  }
}];

const items = $input.all();
return [{
  json: {
    status: 'success',
    tablesProcessed: items.length,
    syncedAt: new Date().toISOString(),
    pipeline: 'clickhouse_to_syntheta'
  }
}];
